INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (6010, "", 21, "", "vo_minigame_1013", "vo_minigame_1013_top_talk_6_001", 6, "", 0, "", 0);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (6011, 0, 11, 0.8, 129911, "マコトさん？\nどうかしましたか？\n何やら不穏な気配を\n感じ取ったのですが", 6, 0, 1, 0, 6);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (6012, "", 91, "", 0, "", 6, "", "", "", "");
