INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (6014, "", 3, "", 129811, "drama_talk_surprise_in_shy", 6, 1, "drama_talk_surprise_loop_shy", 0.2, 0);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (6015, "", 21, "", "vo_minigame_1013", "vo_minigame_1013_top_talk_6_002", 6, "", 0, "", 0);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (6016, 0, 11, 0.3, 129811, "いやいや何でもない！\nあたしは別に変なこと\n考えてないからな！\nそれより訓練だっ！", 6, 0, 1, 0, 9);
