INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (7006, 0, 11, 0.3, 129911, "私の班のみなさんも\n変わらず訓練に励んで\nいるようですわね\n殊勝なことです", 7, 0, 1, 0, 6);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (7007, "", 91, "", 0, "", 7, "", "", "", "");
