INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (7016, 0, 11, 0.5, 129911, "彼らが私に逆らわずに\n努力したからこそ、\n得たものもありますし\n…感謝しておきますわ", 7, 0, 1, 0, 6);
